class BSTNode:
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, data):
        if not self.root:
            self.root = BSTNode(data)
            return
        curr = self.root
        while True:
            if data < curr.data:
                if curr.left:
                    curr = curr.left
                else:
                    curr.left = BSTNode(data)
                    return
            else:
                if curr.right:
                    curr = curr.right
                else:
                    curr.right = BSTNode(data)
                    return

    def search(self, data):
        curr = self.root
        while curr:
            if data == curr.data:
                return True
            elif data < curr.data:
                curr = curr.left
            else:
                curr = curr.right
        return False

    def inorder(self, node):
        if node:
            self.inorder(node.left)
            print(node.data, end=" ")
            self.inorder(node.right)

    def delete(self, data):
        self.root = self._delete(self.root, data)

    def _delete(self, node, data):
        if not node:
            return None
        if data < node.data:
            node.left = self._delete(node.left, data)
        elif data > node.data:
            node.right = self._delete(node.right, data)
        else:
            # Node with only one child or no child
            if not node.left:
                return node.right
            if not node.right:
                return node.left
            # Node with two children
            min_node = self._find_min(node.right)
            node.data = min_node.data
            node.right = self._delete(node.right, min_node.data)
        return node

    def _find_min(self, node):
        curr = node
        while curr.left:
            curr = curr.left
        return curr

