class Graph:
    def __init__(self):
        self.adj = {}

    def add_vertex(self, v):
        if v not in self.adj:
            self.adj[v] = []

    def add_edge(self, u, v, directed=False, weight=None):
        self.add_vertex(u)
        self.add_vertex(v)
        if weight:
            self.adj[u].append((v, weight))
            if not directed:
                self.adj[v].append((u, weight))
        else:
            self.adj[u].append(v)
            if not directed:
                self.adj[v].append(u)

    def dfs(self, start, visited=None):
        if visited is None:
            visited = set()
        visited.add(start)
        print(start, end=" ")
        for neighbor in self.adj.get(start, []):
            if isinstance(neighbor, tuple):
                neighbor = neighbor[0]
            if neighbor not in visited:
                self.dfs(neighbor, visited)

    def bfs(self, start):
        visited = set([start])
        queue = [start]
        while queue:
            v = queue.pop(0)
            print(v, end=" ")
            for neighbor in self.adj.get(v, []):
                if isinstance(neighbor, tuple):
                    neighbor = neighbor[0]
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)

    def has_path(self, start, end, visited=None):
        if visited is None:
            visited = set()
        if start == end:
            return True
        visited.add(start)
        for neighbor in self.adj.get(start, []):
            if isinstance(neighbor, tuple):
                neighbor = neighbor[0]
            if neighbor not in visited:
                if self.has_path(neighbor, end, visited):
                    return True
        return False

