class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_word = False
        self.count = 0  # Track number of words

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TrieNode()
            node = node.children[ch]
            node.count += 1
        node.is_word = True

    def search(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.is_word

    def starts_with(self, prefix):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True

    def count_prefix(self, prefix):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return 0
            node = node.children[ch]
        return node.count

    def delete(self, word):
        self._delete(self.root, word, 0)

    def _delete(self, node, word, index):
        if index == len(word):
            node.is_word = False
            return
        ch = word[index]
        if ch in node.children:
            self._delete(node.children[ch], word, index + 1)
            node.children[ch].count -= 1
            if node.children[ch].count == 0 and not node.children[ch].children:
                del node.children[ch]

    def find_words_with_prefix(self, prefix):
        node = self.root
        for ch in prefix:
            if ch not in node.children:
                return []
            node = node.children[ch]
        words = []
        self._collect_words(node, prefix, words)
        return words

    def _collect_words(self, node, prefix, words):
        if node.is_word:
            words.append(prefix)
        for ch, child in node.children.items():
            self._collect_words(child, prefix + ch, words)

