# Generate all permutations
def permutations(arr):
    def backtrack(path, remaining, result):
        if not remaining:
            result.append(path[:])
            return
        for i in range(len(remaining)):
            path.append(remaining[i])
            backtrack(path, remaining[:i] + remaining[i+1:], result)
            path.pop()

    result = []
    backtrack([], arr, result)
    return result

